-- Chien -> humain, Anniversaire, Volume 10

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Pour ton anniversaire j''ai observé ta façon de souffler les bougies.',$$Pour ton anniversaire j''ai observé ta façon de souffler les bougies.
Tu as pris le temps. Tu as fermé les yeux. Vraiment fermé. Longtemps. Puis tu as soufflé d''un seul coup. Puis tu as regardé si toutes étaient éteintes. Puis tu as souri. Ce sourire-là était pour toi seul. Joyeux anniversaire, mon humain préféré.
Avec respect total pour ton moment du souhait et sa confidentialité préservée, — {prenom}, ton animal témoin de tes moments les plus intimes 🕯️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''étais jaloux du gâteau ce soir.',$$Joyeux anniversaire. J''étais jaloux du gâteau ce soir.
Il a reçu toute l''attention pendant cinq minutes. Tout le monde regardait le gâteau. Tout le monde photographiait le gâteau. Tout le monde voulait une part du gâteau. Moi j''étais là. Accessible. Disponible. Avec des qualités que le gâteau n''a pas. Mais bon. C''était son soir. Je respecte. Joyeux anniversaire, mon humain préféré.
Avec jalousie du gâteau honnêtement avouée et concession faite de bonne grâce, — {prenom}, ton animal second dans les attentions mais premier dans le cœur 🎂$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai suivi chaque bouchée de ton premier morceau de gâteau.',$$Pour ton anniversaire j''ai suivi chaque bouchée de ton premier morceau de gâteau.
La première avec les yeux fermés. La deuxième plus rapide. La troisième avec ce regard qu''on a quand quelque chose est vraiment bon. La quatrième plus détendue. La cinquième avec ce contentement tranquille. Joyeux anniversaire, mon humain préféré.
Avec suivi gastronomique de chaque bouchée et satisfaction de te voir bien manger, — {prenom}, ton animal spécialiste de tes expériences culinaires importantes 🍽️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé ta façon de te tenir quand tu es vraiment fier.',$$Joyeux anniversaire. J''ai observé ta façon de te tenir quand tu es vraiment fier.
Il y a eu un moment ce soir. Quelqu''un a dit quelque chose sur toi. Et tu t''es tenu différemment pendant deux secondes. Plus droit. Plus plein. Comme si ces mots t''avaient ajouté quelque chose. Joyeux anniversaire, mon humain préféré.
Avec observation de tes deux secondes de fierté et validation de leur légitimité totale, — {prenom}, ton animal témoin de tes moments de plénitude 🌟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de saluer quelqu''un que tu aimes beaucoup.',$$Pour ton anniversaire j''ai observé ta façon de saluer quelqu''un que tu aimes beaucoup.
Certains arrivent et tu vas vers eux d''une façon particulière. Plus vite. Avec les bras qui s''ouvrent avant même d''être proche. Cette anticipation du contact. Cette joie qui précède l''accolade. Joyeux anniversaire, mon humain préféré.
Avec identification des accueils anticipés et des personnes qui les méritent, — {prenom}, ton animal cartographe de tes élans 🤗$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai passé la nuit différemment à côté de toi.',$$Pour ton anniversaire j''ai passé la nuit différemment à côté de toi.
Pas au bout du lit. À côté. Contre toi. Je l''ai décidé cette nuit-là. Parce que c''était ton anniversaire. Parce que certains jours méritent une proximité différente. Tu dormais déjà quand je me suis approché. Tu n''as pas bougé. Mais ta respiration a changé légèrement. Comme si tu savais quand même. Joyeux anniversaire, mon humain préféré.
Avec décision de proximité exceptionnelle pour une nuit d''anniversaire et signal reçu dans le sommeil, — {prenom}, ton animal pour les nuits ordinaires et les nuits spéciales ❤️$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les bougies sont de toutes les couleurs.',$$Joyeux anniversaire. Je comprends pas pourquoi les bougies sont de toutes les couleurs.
Roses. Bleues. Jaunes. Vertes. Toutes ensemble sur le même gâteau. Sans cohérence chromatique apparente. Comme si la règle était précisément qu''il n''y ait pas de règle. Que les anniversaires échappent à l''ordre. Dans ce cas je comprends. Joyeux anniversaire, mon humain préféré.
Avec méditation sur le chaos chromatique des bougies et compréhension de sa liberté, — {prenom}, ton animal philosophe des détails festifs 🎨$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de poser tes cadeaux reçus en évidence.',$$Pour ton anniversaire j''ai observé ta façon de poser tes cadeaux reçus en évidence.
Le livre sur la table basse. Le cadre appuyé contre le mur pour décider. La bougie testée sur l''étagère. Chaque cadeau placé là où tu vas le voir. Cette façon de prolonger la joie du cadeau au-delà de la soirée. Joyeux anniversaire, mon humain préféré.
Avec observation de ta façon de prolonger la joie des cadeaux au-delà du soir, — {prenom}, ton animal expert en continuations de bonheur 🎁$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu parlais de moi aux nouveaux invités.',$$Joyeux anniversaire. J''ai observé comment tu parlais de moi aux nouveaux invités.
Il y en avait un ce soir que je n''avais pas encore rencontré. Et tu lui as parlé de moi. Avec cette voix. Celle qui dit que je compte. Que je fais partie de ce que tu es. J''ai entendu ça depuis le couloir. Joyeux anniversaire, mon humain préféré.
Avec écoute de ta présentation de moi et satisfaction pour la façon dont tu le fais, — {prenom}, ton animal fier d''être présenté avec cette voix-là 🐾$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de rire quand tu lis une carte d''anniversaire drôle.',$$Pour ton anniversaire j''ai observé ta façon de rire quand tu lis une carte d''anniversaire drôle.
Pas le rire poli. Le vrai. Celui qui part sans prévenir. Qui te fait fermer les yeux une seconde. Tu as relu la carte deux fois. Tu l''as montrée à quelqu''un. Tu as ri encore. Ce rire-là je le collectionne. Joyeux anniversaire, mon humain préféré.
Avec un vrai rire collectionné ce soir et sa valeur bien établie, — {prenom}, ton animal gardien de tes éclats authentiques 😄$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai gardé le morceau de papier cadeau le plus beau.',$$Pour ton anniversaire j''ai gardé le morceau de papier cadeau le plus beau.
Celui avec les étoiles dorées. Il était tombé par terre pendant que tu déballais. Personne ne l''a ramassé. Moi si. Je l''ai pris dans ma gueule doucement. Je l''ai mis dans mon coin. Il était beau. Je le garde. Joyeux anniversaire, mon humain préféré.
Avec conservation du plus beau papier cadeau et raison entièrement justifiée par sa beauté, — {prenom}, ton animal collectionneur de beautés négligées ⭐$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé ta façon de t''asseoir quand tout le monde est parti.',$$Joyeux anniversaire. J''ai observé ta façon de t''asseoir quand tout le monde est parti.
Pas dans le fauteuil. Sur le canapé. Au milieu. Pas sur le côté. Au milieu. Comme pour occuper tout l''espace de nouveau. Reprendre possession. Et moi qui suis venu m''asseoir juste à côté. Joyeux anniversaire, mon humain préféré.
Avec présence partagée dans la reprise de possession de l''espace post-fête, — {prenom}, ton animal pour les moments de retour à nous deux 🛋️$$,'touching',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de te souvenir de chaque cadeau reçu.',$$Pour ton anniversaire j''ai observé ta façon de te souvenir de chaque cadeau reçu.
Le lendemain tu en parleras avec précision. De qui c''était. Ce que tu as ressenti. L''attention derrière. Cette mémoire des cadeaux qui est en réalité une mémoire des gens qui les ont donnés. Joyeux anniversaire, mon humain préféré, dont la gratitude a une mémoire longue.
Avec anticipation de ta mémoire des cadeaux du lendemain et sa vraie signification, — {prenom}, ton animal admirateur de ta gratitude mémorisée 💛$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé ta façon de chanter avec les autres.',$$Joyeux anniversaire. J''ai observé ta façon de chanter avec les autres.
Tu chantes faux. Je le sais. Je connais ta voix dans tous ses états. Ce soir avec les autres autour du gâteau tu chantais faux et fort et heureux. Cette façon d''assumer. De pas se retenir parce que c''est faux. De chanter quand même parce que le moment le mérite. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ton courage de chanter faux et fort et heureux, — {prenom}, ton animal qui t''a entendu dans toutes tes versions et préfère celle-là 🎵$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens applaudissent après les bougies.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens applaudissent après les bougies.
Les bougies s''éteignent. Et tout le monde applaudit. Pour le souffle. Pour les bougies éteintes. Pour le vœu. Pour toi. Peut-être pour tout ça à la fois. J''aurais aboyé mais c''est le même principe. Joyeux anniversaire, mon humain préféré.
Avec compréhension tardive des applaudissements et reconnaissance de leur équivalent canin, — {prenom}, ton animal philosophe des rituels collectifs 👏$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de regarder ton gâteau avant de le couper.',$$Pour ton anniversaire j''ai observé ta façon de regarder ton gâteau avant de le couper.
Une seconde. Juste une. Avant de prendre le couteau. Comme si tu lui laissais le temps d''exister entier une dernière fois. Comme si couper était un acte qui méritait un moment de contemplation. Joyeux anniversaire, mon humain préféré.
Avec observation de ta seconde de contemplation et admiration pour ta façon d''habiter les avant, — {prenom}, ton animal expert en présence dans les seuils 🎂$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai dormi sur ta chemise de la soirée.',$$Pour ton anniversaire j''ai dormi sur ta chemise de la soirée.
Celle que tu avais portée toute la soirée. Posée sur le dossier après. Encore chaude. Imprégnée de la soirée entière. Je m''y suis installé tard dans la nuit. Comme si dormir là c''était être encore dans la fête. Joyeux anniversaire, mon humain préféré.
Avec occupation de la chemise post-fête et nuit dans les archives de ta soirée, — {prenom}, ton animal qui ne laisse rien des bonnes soirées disparaître tout de suite 👕$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de dire merci pour chaque cadeau.',$$Pour ton anniversaire j''ai observé ta façon de dire merci pour chaque cadeau.
Pas pareil pour chacun. Avec certains c''est court et direct et ça dit tout. Avec d''autres c''est plus long. Plus précis. Tu nommes quelque chose dans le cadeau. Ce qui montre que tu as vu l''attention derrière. Ces mercis personnalisés. Joyeux anniversaire, mon humain préféré.
Avec observation de tes mercis personnalisés et leur signification de reconnaissance vraie, — {prenom}, ton animal expert en gratitude ciblée 🙏$$,'humorous',true,false,'birthday','chien','from'),

(null,'Ce premier moment du lendemain matin où tu te souviens de tout.',$$Ce premier moment du lendemain matin où tu te souviens de tout.
Tu vas te lever demain matin. Et il y aura cette seconde. Cette seconde où ça revient. La soirée. Les gens. Les moments. Et tu vas sourire avant même d''être complètement réveillé. Je serai là. Comme d''habitude. Et on sera heureux tous les deux en même temps sans avoir à se le dire. Joyeux anniversaire, mon humain préféré.
Avec anticipation du moment du lendemain et promesse d''y être pour le partager, — {prenom}, ton animal présent pour tes matins d''après et tous les autres ❤️$$,'touching',true,false,'birthday','chien','from')

on conflict do nothing;
